import logging
from dotenv import load_dotenv
import os
import requests
from datetime import date,  timedelta

load_dotenv()

dia_anterior_obj = date.today() - timedelta(days=1)
dia_atual_obj = date.today()

dia_anterior = dia_anterior_obj.strftime("%d/%m/%Y")
dia_atual = dia_atual_obj.strftime("%d/%m/%Y")

print("Data de ontem: ", dia_anterior)
print("Data de hoje: ", dia_atual)

email = os.getenv("LOGCARE_EMAIL")
password = os.getenv("LOGCARE_PASSWORD")
link_dasa = os.getenv("URL_DASA")
link_rel = os.getenv("URL_RELATORIO")



session = requests.Session()
session.trust_env = False

headers = {
    "User-Agent": "Mozilla/5.0"
}

print("\nIniciando login no Logcare...\n")
#LOGIN NO LOGCARE
login_url = link_dasa
payload = {
    "email": email,
    "senha": password
}
response = session.post(login_url, headers=headers, data=payload)

#Confere se o login foi bem-sucedido
print("Status:", response.status_code)
#print("Cookies:", session.cookies.get_dict())
print("URL final:", response.url)

#Resposta do login
print("\nLogin realizado com sucesso!")

#DOWNLOAD DO RELATORIO SFTP
print("\nBaixando relatório sftp...")
report_url = link_rel

payload_report = {
    "dt_relat_positivacao": dia_atual,
    "i": "bMdBMg==|aFpWODI4MQ==|sSeQMQ==|wYiXMA==|aOiIR2FicmllbCAoQmFzZSk=|aCeNZ2FicmllbC5vMDAxQGhvdG1haWwuY29t||",
    "id_base": "1"
}

report_response = session.post(report_url, data=payload_report)

#Resposta de Download do relatório
print("\n\nReport status:", report_response.status_code, " - Download concluído.")


#Salvar o relatório em um arquivo CSV
with open("data/raw/relatorio.csv", "w", encoding="utf-8") as f:
    f.write(report_response.text)

print("\n\nRelatório salvo!")
print("- - - - - - - - - - - - - - - -")
